arguments.new_str:
using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void ConfigureConventions(ModelConfigurationBuilder configurationBuilder)
    {
        // EF Core 9 renamed "Discriminator" → "$type". Keep the old name so
        // existing 500K documents (and direct SQL queries referencing
        // c.Discriminator) continue to work without a data migration.
        configurationBuilder.Conventions.Remove(
            typeof(Microsoft.EntityFrameworkCore.Cosmos.Metadata.Conventions.CosmosDiscriminatorConvention));
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // Restore the EF Core 8 discriminator property name.
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue<Product>("Product");

            // EF Core 9 no longer prepends the type name to the id.
            // Existing documents use "Product|123", so keep that format.
            entity.HasPartitionKey(p => p.Id);
            entity.Property(p => p.Id)
                  .HasConversion(
                      id => $"Product|{id}",
                      cosmosId => int.Parse(cosmosId.Replace("Product|", "")));

            // EF Core 9 throws on HasIndex for Cosmos (indexes are managed
            // server-side). Replace with an annotation to silence the error.
            // Manage indexing policy in the Azure portal / Bicep / ARM instead.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

