class CosmosQuery
{
    void FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Also uses sync APIs
        var products = ctx.Products.Where(p => p.Sku == "ABC").ToList();
    }
}

arguments.new_str:
class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we preserved "Discriminator"
        // in OnModelCreating (EF Core 9 would otherwise use "$type").
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos removed synchronous APIs (ToList, First, Single, …).
        // All queries must use async equivalents.
        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

