using Microsoft.EntityFrameworkCore;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed.
            // EF Core 9 changed the JSON property from "Discriminator" to "$type".
            // Existing documents and direct SQL queries use "Discriminator",
            // so we explicitly keep the old name.
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue<Product>("Product");

            // BREAKING CHANGE 2 — id format changed.
            // EF Core 9 stores just the raw key ("123") instead of
            // "EntityType|Key" ("Product|123").  Use a value converter to
            // keep reading/writing the legacy format.
            entity.Property(p => p.Id)
                  .HasConversion(
                      id => $"Product|{id}",
                      cosmosId => int.Parse(cosmosId.Replace("Product|", "")));

            // BREAKING CHANGE 3 — HasIndex now throws for Cosmos.
            // The previous HasIndex(p => p.Sku) is removed.
            // Manage the indexing policy in the Azure portal / Bicep / ARM.
        });
    }
}

